S = input()

unique_character = -1
for i in range(len(S)):
    is_unique = True
    for j in range(len(S)):
        if i != j and S[i] == S[j]:
            is_unique = False
            break
    if is_unique:
        unique_character = S[i]
        break

print(unique_character)
